There is a memory leak when using a custom codec. The memory leak seems similar to https://jira.mongodb.org/browse/PYTHON-1554

When using to custom codecs, the memory leak is not there (e.g. when using `type_registry = TypeRegistry() `)

A minimal example reproducing the problem is:
{code:python}#%%
import gc
from typing import Any
from pymongo import MongoClient
from bson.codec_options import CodecOptions
from bson.codec_options import TypeCodec, TypeRegistry

#%% Define method to analyse the memory
def memory_report():
    gc.collect()
    rr={}
    for obj in gc.get_objects():

        tt=type(obj)
        if 'bson' in str(tt):
            rr[tt] = rr.get(tt, 0)+1

    print('memory report:')
    for key in rr:
        nn=rr[key]
        print(f' {key}: {nn}')


#%% Create codec

class MyClass:
    pass

class MyCodec(TypeCodec):  # type: ignore

    pass
    @property
    def python_type(self) -> Any:
         return MyClass

    def transform_python(self, value: Any) -> Any:
        #print(f'transform_python: {value}')
        return value

    @property
    def bson_type(self) -> Any:
         return dict

    def transform_bson(self, value: Any) -> Any:
         #print(f'transform_bson: {value}')
         return value
    
codec=MyCodec()
type_registry = TypeRegistry([codec]) 
codec_options = CodecOptions(type_registry=type_registry) 

client = MongoClient('localhost:27017')
database = client['my_database']
collection = database['my_collection'].with_options(codec_options)

for ii in range(3000):
    cursor = collection.find({})
    for data in cursor:
        pass

_=memory_report() # for multiple iterations objects of type bson.codec_options.CodecOptions are leaking
{code}

On MongoDB 4.4 we rely on the server to supply the {{RetryableWriteError}} error label rather than adding it to the exception in the driver. However, we seem to be ignoring the {{errorLabels}} field returned by the server and as a result, these commands are not retried by the driver. Repro script:

{code:python}
from bson import SON
from pymongo import MongoClient
from pymongo.errors import WriteConcernError
from pymongo.monitoring import CommandListener
import logging


class CommandLogger(CommandListener):
    def started(self, event):
        logging.info("Command {0.command_name} with request id "
                     "{0.request_id} started on server "
                     "{0.connection_id} - {0.command}".format(event))

    def succeeded(self, event):
        logging.info("Command {0.command_name} with request id "
                     "{0.request_id} on server {0.connection_id} "
                     "succeeded in {0.duration_micros} "
                     "microseconds - {0.reply}".format(event))

    def failed(self, event):
        logging.info("Command {0.command_name} with request id "
                     "{0.request_id} on server {0.connection_id} "
                     "failed in {0.duration_micros} "
                     "microseconds".format(event))


logging.basicConfig(level=logging.INFO)


client = MongoClient(directConnection=False, event_listeners=[CommandLogger()])
client.admin.command(SON([('configureFailPoint', 'failCommand'),
                          ('mode', {'times': 1}),
                          ('data', {
                              'failCommands': ['insert'],
                              'writeConcernError': {
                                  'code': 91,
                                  'errmsg': 'Replication is being shut down'}})]))

try:
    client.foo.bar.insert_one({})
except WriteConcernError as exc:
    print(exc._error_labels)
    raise

client.admin.command(SON([('configureFailPoint', 'failCommand'),
                          ('mode', 'off')]))

{code}


